-- =============================================================================
-- CIMScan Migration: Firm Directory Seed + Onboarding Columns
-- Date: 2026-03-05
--
-- Adds:
--   1. New columns on firms (website, phone, address, status)
--   2. Seeds 600 PE firms from industry dataset
--   3. Unique index on ingest_address
--   4. Unique index on website (for new firm registration dedup)
-- =============================================================================

-- ---------------------------------------------------------------------------
-- 1. ADD COLUMNS TO FIRMS
-- ---------------------------------------------------------------------------

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'firms' AND column_name = 'website'
  ) THEN
    ALTER TABLE firms ADD COLUMN website text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'firms' AND column_name = 'phone'
  ) THEN
    ALTER TABLE firms ADD COLUMN phone text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'firms' AND column_name = 'address'
  ) THEN
    ALTER TABLE firms ADD COLUMN address text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'firms' AND column_name = 'status'
  ) THEN
    ALTER TABLE firms ADD COLUMN status text NOT NULL DEFAULT 'active';
  END IF;
END $$;

-- ---------------------------------------------------------------------------
-- 2. SEED PE FIRMS
-- ---------------------------------------------------------------------------

ON CONFLICT DO NOTHING;

-- ---------------------------------------------------------------------------
-- 3. INDEXES
-- ---------------------------------------------------------------------------

-- Unique ingest address (prevents collisions)
CREATE UNIQUE INDEX IF NOT EXISTS idx_firms_ingest_address
  ON firms (LOWER(ingest_address))
  WHERE ingest_address IS NOT NULL;

-- Unique website (prevents duplicate firm registration)
CREATE UNIQUE INDEX IF NOT EXISTS idx_firms_website
  ON firms (LOWER(website))
  WHERE website IS NOT NULL;

-- Search by name (for dropdown autocomplete)
-- Try to enable trigram extension for fuzzy search (may already exist)
CREATE EXTENSION IF NOT EXISTS pg_trgm;

-- Fuzzy search index (works if pg_trgm is available)
CREATE INDEX IF NOT EXISTS idx_firms_name_trgm
  ON firms USING gin (name gin_trgm_ops);

-- Exact prefix search fallback
CREATE INDEX IF NOT EXISTS idx_firms_name_lower
  ON firms (LOWER(name));

-- ---------------------------------------------------------------------------
-- DONE — 600 PE firms seeded
-- ---------------------------------------------------------------------------
